package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithEscapeChar() {
        // Arrange
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char escapeChar = '\\';

        // Act
        CSVFormat result = baseFormat.withEscape(escapeChar);

        // Assert
        assertNotNull(result);
        assertEquals(Character.valueOf(escapeChar), result.getEscapeCharacter());
    }

    @Test
    public void testWithEscapeCharUsingReflection() throws Exception {
        // Arrange
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char escapeChar = 'e';

        // Use reflection to invoke private method withEscape(char)
        Method withEscapeCharMethod = CSVFormat.class.getDeclaredMethod("withEscape", char.class);
        withEscapeCharMethod.setAccessible(true);

        // Act
        CSVFormat result = (CSVFormat) withEscapeCharMethod.invoke(baseFormat, escapeChar);

        // Assert
        assertNotNull(result);
        assertEquals(Character.valueOf(escapeChar), result.getEscapeCharacter());
    }
}
